import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import "../styles/Navbar.css";

const Navbar = () => {
  const { user, isAuthenticated, logout } = useAuth();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate("/login");
    setMenuOpen(false);
  };

  return (
    <nav className="navbar">
      <div className="container navbar-container">
        <Link to="/" className="navbar-logo" onClick={() => setMenuOpen(false)}>
          <span className="logo-icon">🎪</span>
          <span className="logo-text">Svet Igraonica</span>
        </Link>

        <button className="hamburger" onClick={() => setMenuOpen(!menuOpen)}>
          <span></span>
          <span></span>
          <span></span>
        </button>

        <div className={`navbar-links ${menuOpen ? "open" : ""}`}>
          <Link to="/" onClick={() => setMenuOpen(false)}>
            🏠 Početna
          </Link>
          <Link to="/playrooms" onClick={() => setMenuOpen(false)}>
            🎯 Igraonice
          </Link>

          {isAuthenticated ? (
            <>
              <div className="user-badge">
                <span className="user-avatar">👤</span>
                <span className="user-name">{user?.ime}</span>
              </div>

              {user?.role === "roditelj" && (
                <Link to="/my-bookings" onClick={() => setMenuOpen(false)}>
                  📋 Rezervacije
                </Link>
              )}

              {user?.role === "vlasnik" && (
                <>
                  <Link to="/my-playrooms" onClick={() => setMenuOpen(false)}>
                    🏢 Moje igraonice
                  </Link>
                  <Link to="/manage-slots" onClick={() => setMenuOpen(false)}>
                    📅 Termini
                  </Link>
                  <Link
                    to="/create-playroom"
                    onClick={() => setMenuOpen(false)}
                  >
                    ✨ Dodaj igraonicu
                  </Link>
                </>
              )}

              {user?.role === "admin" && (
                <Link to="/admin" onClick={() => setMenuOpen(false)}>
                  ⚙️ Admin panel
                </Link>
              )}

              <button onClick={handleLogout} className="logout-btn">
                🚪 Odjava
              </button>
            </>
          ) : (
            <>
              <Link to="/login" onClick={() => setMenuOpen(false)}>
                🔑 Prijava
              </Link>
              <Link to="/register" onClick={() => setMenuOpen(false)}>
                📝 Registracija
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
